function largestMultipleOfThree(digits) {
    let sum = 0, count = [0, 0, 0];

    for (let d of digits) {
        sum += d;
        count[d % 3]++;
    }

    if (sum % 3 === 1) {
        if (count[1] >= 1) count[1]--; 
        else count[2] -= 2;
    }
    else if (sum % 3 === 2) {
        if (count[2] >= 1) count[2]--;
        else count[1] -= 2;
    }

    let res = "";
    for (let i = 0; i <= 9; ++i) {
        let n = count[i % 3];
        while (n--) res += i;
    }

    if (res.length !== 0 && res[res.length - 1] === '0') return "0";
    return res.split("").reverse().join("");
}
